// ─── RÉCAP AUTOMATIQUE ────────────────────────────────────────────
function buildRecap(service, form){
  const rows = [];
  const t = service.formType;

  if(t==="massage"){
    if(form.technique) rows.push({l:"Technique",v:form.technique});
    let totalQty = 0;
    service.durations?.forEach((d,i)=>{
      const q = form.quantities?.[`dur_${i}`]||0;
      if(q>0){rows.push({l:d.split("—")[0].trim(),v:`${q} pers.`});totalQty+=q;}
    });
    if(form.date) rows.push({l:"Date",v:form.date});
  }
  if(t==="personnes-date"||t==="petit-dej"){
    if(form.duree) rows.push({l:"Durée",v:form.duree});
    if(form.personnes) rows.push({l:"Personnes",v:`${form.personnes} pers.`});
    if(form.date) rows.push({l:"Date",v:form.date});
    if(form.heure) rows.push({l:"Heure",v:form.heure});
  }
  if(t==="courses"){
    if(form.forfait) rows.push({l:"Forfait",v:form.forfait.split("—")[0].trim()});
    if(form.date) rows.push({l:"Date d'arrivée",v:form.date});
  }
  if(t==="devis"){
    if(form.personnes) rows.push({l:"Personnes",v:`${form.personnes} pers.`});
    if(form.date) rows.push({l:"Date & heure",v:form.date?.replace("T"," ")});
  }
  if(t==="dates-seules"){
    rows.push({l:service.nbLabel||"Interventions",v:`${form.nb||1}`});
    if(form.date) rows.push({l:"Date",v:form.date});
  }
  if(form.note) rows.push({l:"Remarques",v:form.note});
  return rows;
}

function isFormValid(service, form){
  const t = service.formType;
  if(t==="massage"){
    const hasQty = service.durations?.some((_,i)=>(form.quantities?.[`dur_${i}`]||0)>0);
    return hasQty && !!form.date;
  }
  if(t==="personnes-date") return !!form.date;
  if(t==="petit-dej") return !!form.date && !!form.heure;
  if(t==="courses") return !!form.forfait && !!form.date;
  if(t==="devis") return !!form.date;
  if(t==="dates-seules") return !!form.date;
  if(t==="menage") return !!form.date && !!form.linge;
  return true;
}

// ─── BOTTOM SHEET ─────────────────────────────────────────────────
function ServiceSheet({service, onClose, onReserve, sent}){
  const [form, setForm] = useState({personnes:1, nb:1});
  const recap = buildRecap(service, form);
  const valid = isFormValid(service, form);

  return <>
    <div className="sheet-overlay" onClick={onClose}/>
    <div className="sheet">
      <button className="btn-close" onClick={onClose}>×</button>
      <div className="sheet-handle"/>
      {service.img
        ? <img src={service.img} className="sheet-img" alt={service.name}/>
        : <div className="sheet-img-ph">{service.icon}</div>
      }
      <div className="sheet-scroll">
        <div className="sheet-content">
          <div className="sheet-cat">✦ Inhérence · Service</div>
          <div className="sheet-title">{service.name}</div>
          <div className="sheet-desc">{service.desc}</div>
          <ServiceForm service={service} form={form} setForm={setForm}/>
          {recap.length > 0 && !sent && <>
            <div className="sheet-divider"/>
            <div className="recap">
              <div className="recap-title">Récapitulatif de votre demande</div>
              {recap.map((r,i)=>(
                <div className="recap-row" key={i}>
                  <span className="recap-label">{r.l}</span>
                  <span className="recap-val">{r.v}</span>
                </div>
              ))}
            </div>
          </>}
          <div style={{height:4}}/>
          <div style={{display:"flex",alignItems:"flex-start",gap:8,padding:"10px 0",borderTop:"1px solid rgba(46,60,77,0.06)",marginTop:4}}>
            <span style={{fontSize:12,flexShrink:0,marginTop:1}}>⚠️</span>
            <span style={{fontSize:9,color:"#9A8F7E",lineHeight:1.6,fontWeight:300,letterSpacing:".03em"}}>{AVAILABILITY_NOTE}</span>
          </div>
          <div style={{height:4}}/>
        </div>
      </div>
      <div className="sheet-footer">
        {sent
          ? <button className="btn-reserve btn-sent">✓ Demande envoyée — votre concierge vous contacte sous 2h</button>
          : <button className={`btn-reserve btn-primary`} onClick={valid?()=>onReserve(recap):undefined} disabled={!valid} style={{opacity:valid?1:.45,cursor:valid?"pointer":"not-allowed"}}>
              <span style={{fontSize:14}}>✦</span> {service.formType==="devis"?"Demander un devis":service.formType==="courses"?"Envoyer ma liste":service.formType==="petit-dej"?"Commander pour ce jour":service.formType==="dates-seules"?"Planifier l'intervention":"Réserver mon soin"}
            </button>
        }
        {!sent && !valid && <div style={{textAlign:"center",fontSize:9,color:"#E3C191",letterSpacing:".1em",textTransform:"uppercase",marginTop:8,opacity:.8}}>Veuillez remplir tous les champs requis</div>}
        {!sent && valid && <div style={{textAlign:"center",fontSize:9,color:"#9A8F7E",letterSpacing:".1em",textTransform:"uppercase",marginTop:8,fontWeight:300}}>Votre concierge vous contacte sous 2h</div>}
      </div>
    </div>
  </>;
}

function Chat({onBack}){
  const [msgs,setMsgs]=useState(MSGS);
  const [val,setVal]=useState("");
  const send=()=>{if(!val.trim())return;setMsgs([...msgs,{text:val,from:"out",time:"maintenant"}]);setVal("");};
  return <div className="chat-wrap fade">
    <SB/>
    <div className="chat-hdr">
      <span className="back" onClick={onBack}>←</span>
      <div className="msg-av" style={{width:34,height:34,fontSize:12}}>IN</div>
      <div><div className="chat-title">Concierge Inhérence</div><div className="chat-online">● disponible</div></div>
    </div>
    <div className="bubbles">
      {msgs.map((m,i)=><div key={i} style={{display:"flex",flexDirection:"column",alignItems:m.from==="out"?"flex-end":"flex-start"}}>
        <div className={`bub bub-${m.from==="out"?"out":"in"}`}>{m.text}</div>
        <div className="bub-time">{m.time}</div>
      </div>)}
    </div>
    <div className="chat-footer">
      <input className="chat-in" placeholder="Votre message..." value={val} onChange={e=>setVal(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send()}/>
      <button className="send" onClick={send}><span style={{color:"#E3C191",fontSize:14}}>➤</span></button>
    </div>
  </div>;
}

