              <button onClick={()=>handleCheckout(r.id,"declined")} style={{flex:1,padding:"11px",borderRadius:10,border:"1px solid rgba(46,60,77,0.12)",background:"transparent",color:"#9A8F7E",fontFamily:"'Montserrat',sans-serif",fontSize:10,fontWeight:300,letterSpacing:".12em",textTransform:"uppercase",cursor:"pointer"}}>Refuser</button>
