function VillaPage(){
  const villaKey = "Bwa Kanpech";
  const villa = VILLA_DATA[villaKey];
  const [expanded, setExpanded] = useState(null);

  const toggle = (id) => setExpanded(e => e===id ? null : id);

  return <div style={{display:"flex",flexDirection:"column",height:"100%"}}>
    {/* Hero */}
    <div style={{position:"relative",height:160,flexShrink:0}}>
      <img src={IVO} style={{width:"100%",height:"100%",objectFit:"cover"}}/>
      <div style={{position:"absolute",inset:0,background:"linear-gradient(to bottom,rgba(46,60,77,0.1),rgba(46,60,77,0.82))"}}/>
      <div style={{position:"absolute",bottom:18,left:22}}>
        <div style={{fontSize:9,letterSpacing:".28em",textTransform:"uppercase",color:"#E3C191",fontWeight:300,marginBottom:5}}>Votre résidence</div>
        <div style={{fontFamily:"'Cormorant Garamond',serif",fontSize:26,fontWeight:200,color:"#FAF8F3",fontStyle:"italic",lineHeight:1}}>{villa.nom}</div>
      </div>
    </div>

    <div style={{flex:1,overflowY:"auto",scrollbarWidth:"none",paddingBottom:20}}>
      {villa.sections.map((sec,si)=>(
        <div key={si}>
          {/* Accordion header */}
          <div onClick={()=>toggle(sec.id)} style={{display:"flex",alignItems:"center",gap:12,padding:"14px 18px",cursor:"pointer",borderBottom:"1px solid rgba(46,60,77,0.06)",background:expanded===sec.id?"#fff":"#FAF8F3",transition:"background .2s"}}>
            <div style={{width:36,height:36,borderRadius:10,background:expanded===sec.id?"#2E3C4D":"#F5ECD8",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0,transition:"background .2s"}}>{sec.icon}</div>
            <div style={{flex:1}}>
              <div style={{fontFamily:"'Cormorant Garamond',serif",fontSize:16,fontWeight:300,color:"#2E3C4D",fontStyle:"italic",letterSpacing:".03em"}}>{sec.title}</div>
            </div>
            <span style={{color:"#E3C191",fontSize:18,transform:expanded===sec.id?"rotate(90deg)":"none",transition:"transform .2s",display:"inline-block"}}>›</span>
          </div>

          {/* Accordion content */}
          {expanded===sec.id&&<div style={{background:"#fff",borderBottom:"1px solid rgba(46,60,77,0.06)"}}>

            {/* Standard items */}
            {sec.items?.map((item,ii)=>(
              <div key={ii} style={{padding:"14px 18px",borderBottom:ii<sec.items.length-1?"1px solid rgba(46,60,77,0.05)":"none"}}>
                <div style={{fontSize:11,fontWeight:500,color:"#2E3C4D",marginBottom:5,letterSpacing:".04em"}}>{item.title}</div>
                <div style={{fontSize:11,color:"#5C6B7A",lineHeight:1.8,fontWeight:300}}>{item.content}</div>
                {item.bullets?.map((b,bi)=>(
                  <div key={bi} style={{display:"flex",alignItems:"flex-start",gap:8,marginTop:6}}>
                    <div style={{width:4,height:4,borderRadius:"50%",background:"#E3C191",marginTop:6,flexShrink:0}}/>
                    <span style={{fontSize:11,color:"#5C6B7A",fontWeight:300,lineHeight:1.7}}>{b}</span>
                  </div>
                ))}
              </div>
            ))}

            {/* État des lieux */}
            {sec.type==="etat"&&<div style={{padding:"16px 18px"}}>
              <div style={{fontSize:11,color:"#5C6B7A",lineHeight:1.8,fontWeight:300,marginBottom:14}}>{sec.content}</div>
              <div style={{background:"#FFF8E1",borderRadius:10,padding:"10px 14px",marginBottom:14,border:"1px solid rgba(227,193,145,0.3)"}}>
                <div style={{fontSize:10,color:"#C9A96E",fontWeight:400,lineHeight:1.6}}>⏱ À compléter dans les 24h suivant votre arrivée. Sans retour de votre part, l'inventaire sera considéré comme validé.</div>
              </div>
              <a href={sec.lien} target="_blank" rel="noopener noreferrer" style={{textDecoration:"none"}}>
                <div style={{width:"100%",padding:"13px",borderRadius:12,background:"#2E3C4D",display:"flex",alignItems:"center",justifyContent:"center",gap:10}}>
                  <span style={{fontSize:14,color:"#E3C191"}}>✦</span>
                  <span style={{fontFamily:"'Montserrat',sans-serif",fontSize:10,color:"#FAF8F3",letterSpacing:".16em",textTransform:"uppercase",fontWeight:400}}>{sec.ctaLabel}</span>
                </div>
              </a>
            </div>}

            {/* Vidéos */}
            {sec.type==="videos"&&<div style={{padding:"12px 18px 16px"}}>
              {sec.videos.map((v,vi)=>(
                <a key={vi} href={v.url} target="_blank" rel="noopener noreferrer" style={{textDecoration:"none"}}>
                  <div style={{display:"flex",alignItems:"center",gap:12,padding:"12px 14px",borderRadius:12,background:"#FAF8F3",border:"1px solid rgba(46,60,77,0.07)",marginBottom:8,cursor:"pointer"}}>
                    <div style={{width:38,height:38,borderRadius:10,background:"#2E3C4D",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>▶</div>
                    <div style={{flex:1,fontSize:11,color:"#2E3C4D",fontWeight:300,lineHeight:1.5}}>{v.label}</div>
                    <span style={{fontSize:12,color:"#E3C191"}}>›</span>
                  </div>
                </a>
              ))}
            </div>}

            {/* Lieux / Quartier */}
            {sec.type==="lieux"&&<div style={{padding:"12px 18px 16px"}}>
              {sec.lieux.map((l,li)=>(
                <div key={li} style={{marginBottom:8}}>
                  {l.url
                    ? <a href={l.url} target="_blank" rel="noopener noreferrer" style={{textDecoration:"none"}}>
                        <div style={{display:"flex",alignItems:"center",gap:12,padding:"12px 14px",borderRadius:12,background:"#FAF8F3",border:"1px solid rgba(46,60,77,0.07)"}}>
                          <div style={{width:36,height:36,borderRadius:10,background:"#F5ECD8",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>{l.icon}</div>
                          <div style={{flex:1}}>
                            <div style={{fontSize:12,color:"#2E3C4D",fontWeight:400}}>{l.nom}</div>
                            <div style={{fontSize:10,color:"#9A8F7E",marginTop:2,fontWeight:300}}>{l.detail}</div>
                          </div>
                          <div style={{display:"flex",alignItems:"center",gap:4,background:"#2E3C4D",borderRadius:8,padding:"5px 10px"}}>
                            <span style={{fontSize:10,color:"#E3C191",fontWeight:300,letterSpacing:".06em"}}>Y aller</span>
                            <span style={{fontSize:11,color:"#E3C191"}}>↗</span>
                          </div>
                        </div>
                      </a>
                    : <div style={{display:"flex",alignItems:"center",gap:12,padding:"12px 14px",borderRadius:12,background:"#FAF8F3",border:"1px solid rgba(46,60,77,0.07)"}}>
                        <div style={{width:36,height:36,borderRadius:10,background:"#F5ECD8",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0}}>{l.icon}</div>
                        <div style={{flex:1}}>
                          <div style={{fontSize:12,color:"#2E3C4D",fontWeight:400}}>{l.nom}</div>
                          <div style={{fontSize:10,color:"#9A8F7E",marginTop:2,fontWeight:300}}>{l.detail}</div>
                        </div>
                        <div style={{padding:"5px 10px",borderRadius:8,background:"rgba(46,60,77,0.05)"}}>
                          <span style={{fontSize:10,color:"#9A8F7E",letterSpacing:".06em"}}>Bientôt</span>
                        </div>
                      </div>
                  }
                </div>
              ))}
            </div>}

          </div>}
        </div>
      ))}
    </div>
  </div>;
}

